function Alert({ message }) {
  return (
    <div className="alert">
      <strong>Notice:</strong> {message}
    </div>
  );
}

// What the compiler produces:
function Alert({ message }) {
  return React.createElement(
    "div",
    { className: "alert" },
    React.createElement("strong", null, "Notice:"),
    " ",
    message
  );
}

