exercise.solution:
const weather = {
  city: "Lisbon",
  temp: 28,
  condition: "Sunny",
};

function WeatherCard() {
  return (
    <>
      <h2>{weather.city}</h2>
      <p>{weather.temp} °C</p>
      <span className="condition">{weather.condition}</span>
    </>
  );
}

export default WeatherCard;
